import{_ as t,o as a,c as o,ak as i}from"./chunks/framework.Dx0ZwfXr.js";const m=JSON.parse('{"title":"ExternalSessionConfiguration","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-rdp-winforms-configuration-external-externalsessionconfiguration.md","filePath":"api/reference/royalapps-community-rdp-winforms-configuration-external-externalsessionconfiguration.md"}'),r={name:"api/reference/royalapps-community-rdp-winforms-configuration-external-externalsessionconfiguration.md"};function s(n,e,d,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="externalsessionconfiguration" tabindex="-1"><code>ExternalSessionConfiguration</code> <a class="header-anchor" href="#externalsessionconfiguration" aria-label="Permalink to “ExternalSessionConfiguration”">​</a></h1><p>Configuration for launching an external Remote Desktop client process. Support: external sessions only.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.Rdp.WinForms.Configuration.External.ExternalSessionConfiguration</span></span></code></pre></div><h2 id="used-by" tabindex="-1">Used By <a class="header-anchor" href="#used-by" aria-label="Permalink to “Used By”">​</a></h2><ul><li><a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-rdpclientconfiguration">RdpClientConfiguration</a></li></ul><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="additionalarguments-string" tabindex="-1"><code>AdditionalArguments</code> (<code>string</code>?) <a class="header-anchor" href="#additionalarguments-string" aria-label="Permalink to “AdditionalArguments (string?)”">​</a></h3><p>Gets or sets additional command-line arguments appended after the generated <code>.rdp</code> file path.</p><h3 id="additionalmsrdpexsettings-collection-rdpfilesetting" tabindex="-1"><code>AdditionalMsRdpExSettings</code> (<code>Collection</code>&lt;<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-external-files-rdpfilesetting">RdpFileSetting</a>&gt;) <a class="header-anchor" href="#additionalmsrdpexsettings-collection-rdpfilesetting" aria-label="Permalink to “AdditionalMsRdpExSettings (Collection&lt;RdpFileSetting&gt;)”">​</a></h3><p>Gets additional MsRdpEx-specific RDP settings that are appended after the built-in mapping when <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-external-externalsessionconfiguration">ExternalSessionConfiguration.UseMsRdpExHooks</a> is enabled.</p><h3 id="additionalrdpsettings-collection-rdpfilesetting" tabindex="-1"><code>AdditionalRdpSettings</code> (<code>Collection</code>&lt;<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-external-files-rdpfilesetting">RdpFileSetting</a>&gt;) <a class="header-anchor" href="#additionalrdpsettings-collection-rdpfilesetting" aria-label="Permalink to “AdditionalRdpSettings (Collection&lt;RdpFileSetting&gt;)”">​</a></h3><p>Gets additional standard RDP settings that are appended after the built-in mapping.</p><h3 id="closetimeout-timespan" tabindex="-1"><code>CloseTimeout</code> (<code>TimeSpan</code>) <a class="header-anchor" href="#closetimeout-timespan" aria-label="Permalink to “CloseTimeout (TimeSpan)”">​</a></h3><p>Gets or sets the amount of time to wait for a graceful shutdown after requesting the external process to close.</p><h3 id="credentialtarget-string" tabindex="-1"><code>CredentialTarget</code> (<code>string</code>?) <a class="header-anchor" href="#credentialtarget-string" aria-label="Permalink to “CredentialTarget (string?)”">​</a></h3><p>Gets or sets the credential target name. When not set, a <code>TERMSRV/...</code> target is derived from the configured server and port.</p><h3 id="keeptemporaryrdpfile-bool" tabindex="-1"><code>KeepTemporaryRdpFile</code> (<code>bool</code>) <a class="header-anchor" href="#keeptemporaryrdpfile-bool" aria-label="Permalink to “KeepTemporaryRdpFile (bool)”">​</a></h3><p>Gets or sets a value indicating whether the generated <code>.rdp</code> file should be kept after the session ends.</p><h3 id="killprocessondisconnect-bool" tabindex="-1"><code>KillProcessOnDisconnect</code> (<code>bool</code>) <a class="header-anchor" href="#killprocessondisconnect-bool" aria-label="Permalink to “KillProcessOnDisconnect (bool)”">​</a></h3><p>Gets or sets a value indicating whether <code>System.Diagnostics.Process.Kill(System.Boolean)</code> should be used if graceful shutdown does not finish within <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-external-externalsessionconfiguration">ExternalSessionConfiguration.CloseTimeout</a>.</p><h3 id="killprocessonhostexit-bool" tabindex="-1"><code>KillProcessOnHostExit</code> (<code>bool</code>) <a class="header-anchor" href="#killprocessonhostexit-bool" aria-label="Permalink to “KillProcessOnHostExit (bool)”">​</a></h3><p>Gets or sets a value indicating whether the external process should be assigned to a Windows job so it is terminated when the host process exits unexpectedly.</p><h3 id="msrdpexlauncherpath-string" tabindex="-1"><code>MsRdpExLauncherPath</code> (<code>string</code>?) <a class="header-anchor" href="#msrdpexlauncherpath-string" aria-label="Permalink to “MsRdpExLauncherPath (string?)”">​</a></h3><p>Gets or sets the full path to <code>mstscex.exe</code>. When not set, well-known installation folders are probed.</p><h3 id="msrdpexsearchpaths-collection-string" tabindex="-1"><code>MsRdpExSearchPaths</code> (<code>Collection</code>&lt;<code>string</code>&gt;) <a class="header-anchor" href="#msrdpexsearchpaths-collection-string" aria-label="Permalink to “MsRdpExSearchPaths (Collection&lt;string&gt;)”">​</a></h3><p>Gets additional directories or full file paths that should be probed for <code>mstscex.exe</code> before the built-in well-known installation folders. Support: external sessions through MsRdpEx only. This is intended for app-local deployment scenarios where the MsRdpEx release files are shipped next to the host application.</p><h3 id="mstscpath-string" tabindex="-1"><code>MstscPath</code> (<code>string</code>?) <a class="header-anchor" href="#mstscpath-string" aria-label="Permalink to “MstscPath (string?)”">​</a></h3><p>Gets or sets the full path to <code>mstsc.exe</code>. When not set, the system default is used.</p><h3 id="selectedmonitors-string" tabindex="-1"><code>SelectedMonitors</code> (<code>string</code>?) <a class="header-anchor" href="#selectedmonitors-string" aria-label="Permalink to “SelectedMonitors (string?)”">​</a></h3><p>Gets or sets the comma-separated monitor identifiers written to the <code>selectedmonitors</code> RDP property. This setting is only applied in external mode and requires multi-monitor mode. Monitor identifiers can be discovered with <code>mstsc.exe /l</code>. Embedded mode rejects this value instead of trying to approximate the monitor layout.</p><h3 id="temporarydirectory-string" tabindex="-1"><code>TemporaryDirectory</code> (<code>string</code>?) <a class="header-anchor" href="#temporarydirectory-string" aria-label="Permalink to “TemporaryDirectory (string?)”">​</a></h3><p>Gets or sets the directory used for the temporary <code>.rdp</code> file. When not set, the system temp directory is used.</p><h3 id="usecredentialmanager-bool" tabindex="-1"><code>UseCredentialManager</code> (<code>bool</code>) <a class="header-anchor" href="#usecredentialmanager-bool" aria-label="Permalink to “UseCredentialManager (bool)”">​</a></h3><p>Gets or sets a value indicating whether a credential should be materialized in the Windows credential manager before launch.</p><h3 id="usemsrdpexhooks-bool" tabindex="-1"><code>UseMsRdpExHooks</code> (<code>bool</code>) <a class="header-anchor" href="#usemsrdpexhooks-bool" aria-label="Permalink to “UseMsRdpExHooks (bool)”">​</a></h3><p>Gets or sets a value indicating whether the external connection should be launched through <code>mstscex.exe</code> when it is available.</p><p><a href="./../">Back to API index</a></p>',38)])])}const g=t(r,[["render",s]]);export{m as __pageData,g as default};
